import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote - base premiums", () => {
    it.todo("returns 5 G for an empty item list (processing fee only)");
    it.todo("returns 105 G for a single sword (100 base + 5 fee)");
    it.todo("returns 65 G for a single amulet (60 base + 5 fee)");
    it.todo("returns 85 G for a single staff (80 base + 5 fee)");
    it.todo("returns 45 G for a single potion (40 base + 5 fee)");
    it.todo("returns 165 G for a sword and an amulet (100 + 60 + 5 fee)");
  });

  describe("Quote - component premiums", () => {
    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
    it.todo("returns 65 G for 3 alike runes (60 block premium + 5 fee)");
    it.todo("returns 105 G for 4 runes (no block: 4 * 25 = 100 + 5 fee)");
    it.todo("returns 80 G for 2 runes + 1 moonstone (no block: different types, 75 + 5 fee)");
    it.todo("returns 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
  });

  describe("Quote - cursed surcharge", () => {
    it.todo("adds 50% surcharge to a cursed sword (100 + 50 + 5 fee = 155 G)");
    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
  });

  describe("Quote - high enchantment surcharge", () => {
    it.todo("adds 30% surcharge for enchantment level 5 (100 + 30 + 5 fee = 135 G)");
    it.todo("does not add surcharge for enchantment level 4");
    it.todo("applies both cursed and high enchantment surcharges to the same item");
  });

  describe("Quote - loyalty discount", () => {
    it.todo("applies 20% loyalty discount for customer with 2 years");
    it.todo("does not apply loyalty discount for customer with 1 year");
  });

  describe("Quote - first insurance surcharge", () => {
    it.todo("adds 10% first insurance surcharge on policy base premium");
  });

  describe("Quote - follow-up contract discount", () => {
    it.todo("applies 15% follow-up discount on second quote in scenario");
  });

  describe("Quote - rounding", () => {
    it.todo("rounds premium up in MHPCO's favor (ceiling)");
  });

  describe("Quote - integration", () => {
    it.todo("newcomer with cursed sword: 165 G");
    it.todo("long-standing customer second contract with cursed enchanted sword: 160 G");
  });

  describe("Quote - errors", () => {
    it.todo("throws error for unknown item type");
  });

  describe("Claim - basic payout", () => {
    it.todo("applies 100 G deductible per damaged item");
    it.todo("fully reimburses standard item damage minus deductible");
  });

  describe("Claim - dragon material", () => {
    it.todo("fully reimburses damage to dragon material items minus deductible");
  });

  describe("Claim - high enchantment reimbursement", () => {
    it.todo("reimburses 50% of damage for enchantment >= 8, then applies deductible");
    it.todo("50% rule wins over dragon material when enchantment >= 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across multiple claims on same policy");
  });

  describe("Claim - multiple damages in one event", () => {
    it.todo("applies deductible per damaged item in same event");
    it.todo("handles two damages of same item type when policy covers two");
  });

  describe("Claim - payout rounding", () => {
    it.todo("rounds payout down in MHPCO's favor (floor)");
  });

  describe("Claim - errors", () => {
    it.todo("rejects damage for item type not in policy");
    it.todo("rejects more damages of a type than policy covers");
    it.todo("rejects negative damage amount");
  });
});

