    it.todo("reimburses 50% of damage for enchantment >= 8, then applies deductible");
    it.todo("50% rule wins over dragon material when enchantment >= 8");
  });

  describe("Claim - cap", () => {
    it.todo("caps total payout at twice the insurance sum");
    it.todo("tracks remaining cap across multiple claims on same policy");
  });

  describe("Claim - multiple damages in one event", () => {
    it.todo("applies deductible per damaged item in same event");
    it.todo("handles two damages of same item type when policy covers two");
  });

  describe("Claim - payout rounding", () => {
