const calculateClaimPayout = (damages: any[]): number => {
  let payout = 0;
  for (const damage of damages) {
    payout += Math.max(0, damage.amount - DEDUCTIBLE);
  }
  return payout;
};

export const processScenario = (scenario: any): any => ({
  results: scenario.steps.map((step: any, index: number) => {
    if (step.op === "claim") {
      return { payout: calculateClaimPayout(step.damages) };
    }
    return { premium: calculateQuotePremium(step.items, scenario.customer, index) };
  }),
});

